final:
module gray_code_counter_4(
   input                clk,
   input                rst_n,

   output reg [3:0]     Q
);
    reg [3:0] unused_binary_count;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            unused_binary_count <= 4'b0000;
            Q <= 4'b0000;
        end else begin
            unused_binary_count <= unused_binary_count + 1;
            Q <= unused_binary_count ^ (unused_binary_count >> 1);
        end
    end
endmodule
